completion:
{
  "task_id": "heavy_hitter_threshold_fallback",
  "task_description": "验证 heavy hitter 检测功能。可以在测试前由人工把交换机的阈值临时调低到 10。然后让 h1 向 h2 发送同一条五元组 TCP 流，期望前 10 个包可以转发，第 11 个及之后的包被丢弃；另外再生成一个不同五元组的新 TCP 流，期望它不受前一条流影响。",
  "feature_under_test": "forwarding_behavior",
  "intent_category": "stateful_policy",
  "observation_focus": null,
  "observation_method": null,
  "expected_observation_semantics": null,
  "operator_actions": [
    {
      "order": 1,
      "action_type": "manual_threshold_override",
      "timing": "before_traffic",
      "scenario": null,
      "target": "PACKET_THRESHOLD",
      "parameters": {
        "new_value": 10
      },
      "expected_effect": "threshold is lowered to 10 before traffic begins"
    }
  ],
  "observation_requirements": [],
  "traffic_pattern": null,
  "role_bindings": {
    "initiator": "h1",
    "responder": "h2"
  },
  "sequence_contract": [
    {
      "scenario": "positive_below_threshold",
      "kind": "positive",
      "required": true,
      "scenario_goal": "send a repeated TCP flow below the heavy-hitter threshold and observe forwarding",
      "expected_observation": null,
      "steps": [
        {
          "tx_role": "initiator",
          "rx_role": "responder",
          "protocol_stack": [
            "Ethernet",
            "IPv4",
            "TCP"
          ],
          "repeat_count": 10,
          "traffic_profile": "same_flow_below_threshold",
          "field_expectations": {
            "TCP.sport": "fixed_to_congest_flow",
            "TCP.dport": 80,
            "TCP.flags": {
              "one_of": [
                "0x02",
                2,
                "SYN"
              ]
            }
          }
        }
      ],
      "field_relations": [],
      "allow_additional_packets": false
    },
    {
      "scenario": "negative_threshold_exceeded",
      "kind": "negative",
      "required": true,
      "scenario_goal": "continue the same TCP flow beyond the threshold and expect drop behavior",
      "expected_observation": null,
      "steps": [
        {
          "tx_role": "initiator",
          "rx_role": "responder",
          "protocol_stack": [
            "Ethernet",
            "IPv4",
            "TCP"
          ],
          "repeat_count": 2,
          "traffic_profile": "same_flow_above_threshold",
          "field_expectations": {
            "TCP.sport": "fixed_to_congest_flow",
            "TCP.dport": 80,
            "TCP.flags": {
              "one_of": [
                "0x02",
                2,
                "SYN"
              ]
            }
          }
        }
      ],
      "field_relations": [],
      "allow_additional_packets": false
    },
    {
      "scenario": "positive_different_flow",
      "kind": "positive",
      "required": true,
      "scenario_goal": "send a different TCP flow and verify it is not affected by the previous heavy hitter",
      "expected_observation": null,
      "steps": [
        {
          "tx_role": "initiator",
          "rx_role": "responder",
          "protocol_stack": [
            "Ethernet",
            "IPv4",
            "TCP"
          ],
          "repeat_count": 2,
          "traffic_profile": "different_five_tuple_new_flow",
          "field_expectations": {
            "TCP.sport": "new_flow_different_hash",
            "TCP.dport": 8080,
            "TCP.flags": {
              "one_of": [
                "0x02",
                2,
                "SYN"
              ]
            }
          }
        }
      ],
      "field_relations": [],
      "allow_additional_packets": false
    }
